+        /// This is the table type of the record that was modified.
+        /// This is intentionally represented as an int in order to avoid serialization issues
+        /// </summary>
+        public int TableType { get; set; }
+
+        /// <summary>
+        /// The primary key of the record that was modified.
+        /// </summary>
+        public int RecordId { get; set; }
+
+        /// <summary>
+        /// The record's guid. Primarily for use in new records
+        /// </summary>
+        public Guid Guid { get; set; }
+
+        /// <summary>
+        /// This is the table type of the parent of the record that was modified if the record is not a direct child of the top level record.
+        /// This is intentionally represented as an int in order to avoid serialization issues
+        /// </summary>
+        public int ParentTableType { get; set; }
+
+        /// <summary>
+        /// The guid of the parent of the record that was modified if the record is not a direct child of the top level record. Primarily for use in new records
+        /// </summary>
+        public Guid ParentGuid { get; set; }
+
+        /// <summary>
+        /// The primary action that occurred on this record
+        /// </summary>
+        public ChangeTypes Change { get; set; }
+
+        /// <summary>
+        /// The list of fields that changed
+        /// </summary>
+        public IDictionary<string, object> FieldUpdates => m_FieldUpdates;
+        #endregion Properties
