+            // Exceptions are handled by the caller
+
+            // Always send all records for company, deleted or not.
+            // This allows mobile to display references to deleted companies and contacts 
+            // For example, the Author field of a record might reference a former project member
+
+            var okToTruncate = record.TableType != (int)PrologTable.Types.Company;
+
+            if (Change == ChangeTypes.Add && record.ActionType == HistoryRecord.ActionTypes.Delete)
+            {
+                Truncate = okToTruncate;
+            }
+
+            if (Change == ChangeTypes.Add && record.ActionType == HistoryRecord.ActionTypes.Modify)
+            {
+                // Do not adjust the action type
+            }
+            else
+            {
+                Change = (ChangeTypes)record.ActionType;
+            }
+
+            if (okToTruncate && record.ActionType == HistoryRecord.ActionTypes.Delete)
+            {
+                // Clear all field changes on a delete
+                m_FieldUpdates.Clear();
+            }
+#if needed
+            else
+            {
+                foreach (var field in record.FieldChanges)
+                {
+                    m_FieldUpdates.AddOrUpdateField(field.Name, field.NewValue);
+                }
+
+                ContactProjectLinks_Patch(record, history);
+            }
+
+            // Ensure the timestamps exist for mobile
+            if (record.ActionType == HistoryRecord.ActionTypes.Add)
+            {
+                m_FieldUpdates.AddOrUpdateField("WhenCreated", history.LastModified);
+                m_FieldUpdates.AddOrUpdateField("CreatedBy", history.LastModifiedBy);
+                m_FieldUpdates.AddOrUpdateField("CreatedByContactID", history.LastModifiedByContactID);
+                m_FieldUpdates.AddOrUpdateField("CreatedByUserID", history.LastModifiedByUserID);
+            }
+
+            m_FieldUpdates.AddOrUpdateField("LastModified", history.LastModified);
+            m_FieldUpdates.AddOrUpdateField("LastModifiedBy", history.LastModifiedBy);
+            m_FieldUpdates.AddOrUpdateField("LastModifiedByContactID", history.LastModifiedByContactID);
+            m_FieldUpdates.AddOrUpdateField("LastModifiedByUserID", history.LastModifiedByUserID);
+#else
+            else
+            {
+                foreach (var field in record.FieldChanges)
+                {
+                    m_FieldUpdates[field.Name] = field.NewValue;
+                }
+
+                ContactProjectLinks_Patch(record, history);
+            }
+
+            // Ensure the timestamps exist for mobile
+            if (record.ActionType == HistoryRecord.ActionTypes.Add)
+            {
+                m_FieldUpdates["WhenCreated"] = history.LastModified;
+                m_FieldUpdates["CreatedBy"] =  history.LastModifiedBy;
+                m_FieldUpdates["CreatedByContactID"] = history.LastModifiedByContactID;
+                m_FieldUpdates["CreatedByUserID"] = history.LastModifiedByUserID;
+            }
+
+            m_FieldUpdates["LastModified"] = history.LastModified;
+            m_FieldUpdates["LastModifiedBy"] = history.LastModifiedBy;
+            m_FieldUpdates["LastModifiedByContactID"] = history.LastModifiedByContactID;
+            m_FieldUpdates["LastModifiedByUserID"] = history.LastModifiedByUserID;
+#endif
+        }
