+        {
+            // Previously, when history was calculated from a Project Directory (Project Contact Link) 
+            // the resulting history record (on company with child of Contact Project Link) did not include Project ID.
+            // Instead, the Project ID was encoded into the History record as a whole.   
+
+            // The Project ID in the history record might or might not get sent to the client .. it depends 
+            // on whether history record was the first record for the Company or not.
+
+            // But even if it was sent, the client effectively ignored the Project ID at the history record level.
+
+            // This code backfills the Project ID into the Contact Project Link so that link is can be created 
+            // correctly in mobile or any other client. 
+
+            if (history.ProjectId == 0) return;
+            if (history.TableType != (int)PrologTable.Types.Company) return;
+            if (record.TableType != (int)PrologTable.Types.ContactProjectLink) return;
+            if (record.ActionType != HistoryRecord.ActionTypes.Add) return;
+            if (m_FieldUpdates.ContainsKey(nameof(ContactProjectLink.ProjectID))) return; // already has a ProjectID 
+
+#if needed
+            m_FieldUpdates.AddOrUpdateField(nameof(ContactProjectLink.ProjectID), history.ProjectId);
+#else
+            m_FieldUpdates[nameof(ContactProjectLink.ProjectID)] = history.ProjectId;
+#endif
+        }
