+#if needed
+#region DeltaItemConverter
+    public class DeltaItemConverter : JsonConverter
+    {
+        public override bool CanConvert(Type objectType)
+        {
+            return objectType == typeof(DeltaItem);
+        }
+
+        public override object ReadJson(JsonReader reader, Type objectType, object existingValue, JsonSerializer serializer)
+        {
+            var item = existingValue != null ? (DeltaItem)existingValue : new DeltaItem();
+
+            var contents = serializer.Deserialize<Dictionary<string, object>>(reader);
+
+            foreach(var property in contents)
+            {
+                switch(property.Key)
+                {
+                    case "@" + nameof(item.TableType): item.TableType = (int)property.Value; break;
+                    case "@" + nameof(item.Guid): item.Guid = Guid.Parse((string)property.Value); break;
+                    case "@" + nameof(item.RecordId): item.RecordId = (int)property.Value; break;
+                    case "@" + nameof(item.ParentGuid): item.ParentGuid = Guid.Parse((string)property.Value); break;
+                    case "@" + nameof(item.Change): item.Change = (DeltaItem.ChangeTypes)(int)property.Value; break;
+                    default: item.FieldUpdates.Add(property.Key, property.Value); break;
+                }
+            }
+
+            return item;
+        }
+
+        public override void WriteJson(JsonWriter writer, object value, JsonSerializer serializer)
+        {
+            var item = (DeltaItem)value;
+
+            writer.WriteStartObject();
+            writer.WritePropertyName("@" + nameof(item.TableType)); writer.WriteValue((int)item.TableType);
+            writer.WritePropertyName("@" + nameof(item.Guid)); writer.WriteValue(item.Guid);
+            writer.WritePropertyName("@" + nameof(item.RecordId)); writer.WriteValue(item.RecordId);
+            writer.WritePropertyName("@" + nameof(item.ParentGuid)); writer.WriteValue(item.ParentGuid);
+            writer.WritePropertyName("@" + nameof(item.Change)); writer.WriteValue((int)item.Change);
+
+            foreach(var update in item.FieldUpdates)
+            {
+                writer.WritePropertyName(update.Key); writer.WriteValue(update.Value);
+            }
+
+            writer.WriteEndObject();
+        }
+    }
+#endregion DeltaItemConverter
+#endif
