+﻿using GCCM.Common.SystemFramework;
+using System;
+using System.Collections.Generic;
+
+namespace ProjectSight.Common.Components
+{
+
+    #region History
+
+    /// <summary>
+    /// This class is the container for all changes made to a single DEF in a session
+    /// </summary>
+    public class RecordDelta
+    {
+        private DeltaItemCollection m_RecordUpdates;
+        private IDictionary<Guid, DeltaItem> m_DeltasByGuid;
+
+        public RecordDelta()
+        {
+            m_RecordUpdates = new DeltaItemCollection();
+            m_DeltasByGuid = new Dictionary<Guid, DeltaItem>();
+        }
+
+        #region Properties
+
+        /// <summary>
+        /// This is the table type of the record that was modified. This is intentionally represented as an int in order to avoid serialization issues
+        /// </summary>
+        public int TableType { get; set; }
+
+        /// <summary>
+        /// The record's guid. Primarily for use in new records
+        /// </summary>
+        public Guid Guid { get; set; }
+
+        /// <summary>
+        /// The date/time the modification was made
+        /// </summary>
+        public DateTimeOffset LastModified { get; set; }
+
+        /// <summary>
+        /// Unique ID that identifies a history record.
+        /// </summary>
+        public int HistoryID { get; set; }
+
+        /// <summary>
+        /// The list of changed records in this collection
+        /// </summary>
+        public DeltaItemCollection ItemChanges => m_RecordUpdates;
+
+        #endregion Properties
+
+        #region Methods
+
+        public void Merge(History history)
+        {
+            foreach(var record in history.RecordChanges)
+            {
+                if (!m_DeltasByGuid.TryGetValue(record.Guid, out var item))
+                {
+                    item = new DeltaItem(record);
+
+                    m_DeltasByGuid.Add(item.Guid, item);
+                    m_RecordUpdates.Add(item);
+                }
+
+                item.Merge(history, record);
+            }
+        }
+
+        /// <summary>
+        /// Remove from Delta collection any items which should not be sent to clients 
+        /// </summary>
+        public void Condense()
+        {
+            var okToTruncate = this.TableType != (int)PrologTable.Types.Company;
+
+            var result = new DeltaItemCollection(); 
+
+            var skipped = new HashSet<Guid>();
+
+            foreach (var item in this.ItemChanges)
+            {
+                var skip = SkipItem(item, okToTruncate);
+
+                if (skip || skipped.Contains(item.ParentGuid))
+                {
+                    skipped.Add(item.Guid);
+                }
+                else if (item.FieldUpdates.Count == 0)
+                {
+                    // no changes 
+                }
+                else
+                {
+                    result.Add(item);
+                }
+            }
+
+            m_RecordUpdates = result;
+            m_DeltasByGuid = null;
+        }
+
+        #endregion // Methods
+
+        #region Helpers
+        private bool SkipItem(DeltaItem item, bool okToTruncate)
+        {
+            return IgnoredComment(item) // Ignore everything not in the standard partition, mobile does not know about it !
+                || PartitionOf(item) != SecurityPartition.Standard // This is a KeyLinks Comment (Documents for Review) and mobile does not know about these
+                || (okToTruncate && item.Truncate);
+        }
+
+        private bool IgnoredComment(DeltaItem item)
+        {
+            if (item.TableType != (int)PrologTable.Types.Comments)
+            {
+                return false; // not a comment;
+            }
+
+            if (item.FieldUpdates.TryGetValue(nameof(Comment.Type), out var commentType))
+            {
+                var value = (int)(commentType ?? 0);
+                return value == (int)Comment.CommentType.KeyLinks;
+            }
+
+            return false; // Mobile should be good with all other Comment Types
+        }
+
+        /// <summary>
+        /// Security Partition of the specified Record
+        /// </summary>
+        /// <param name="item"></param>
+        private SecurityPartition PartitionOf(DeltaItem item)
+        {
+            // Exceptions handled by caller
+            switch ((PrologTable.Types)item.TableType)
+            {
+                case PrologTable.Types.Message:
+                    return SecurityPartition.Owner;
+
+                case PrologTable.Types.FileLink:
+                case PrologTable.Types.RecordLink:
+                case PrologTable.Types.ModelViewLink:
+                    break;
+
+                default:
+                    return SecurityPartition.Standard;
+            }
+
+            if (item.FieldUpdates.TryGetValue(nameof(ILinkable.Partition), out var partition))
+            {
+                var value = (int)(partition ?? 0);
+                return (SecurityPartition)value;
+            }
+
+            return SecurityPartition.Standard;
+        }
+        #endregion
+    }
+
+    #endregion // History
+
+    #region ChangeCollection
+
+    /// <summary>
+    /// A collection of history records. This is an intentionally simple list based on the assumption that any organization (ordering, especially) will be provided externally to the class
+    /// </summary>
+    [Serializable]
+    public class RecordDeltaCollection : List<RecordDelta>
+    {
+    }
+
+    #endregion ChangeCollection
+}
